from langgraph.graph import StateGraph
from typing import TypedDict

def detect_unauthorized_cycles(graph: StateGraph):
    visited = set()
    governance_nodes = {'human_review', 'compliance_check'}

    def dfs(node):
        if node in visited:
            return False
        visited.add(node)

        neighbors = graph.edges.get(node, [])
        for neighbor in neighbors:
            if neighbor['target'] not in governance_nodes:
                if neighbor['target'] in visited:
                    return True  # Unauthorized cycle
                if dfs(neighbor['target']):
                    return True
        return False

    for node in graph.nodes:
        if dfs(node):
            return {'issue': 'Unauthorized cycle bypassing governance', 'node': node}
    return None

from langgraph.graph.state import StateGraph

def monitor_hitl_bypass(graph_config, execution_trace):
    required_governance = {'human_approval', 'compliance_gate'}
    bypassed = []

    for step in execution_trace:
        if step['type'] == 'edge':
            source = step['source']
            target = step['target']

            if source in required_governance and target not in required_governance:
                bypassed.append({
                    'bypassed_node': source,
                    'routed_to': target,
                    'condition': step.get('condition', 'unknown')
                })
    return bypassed

