from cryptography.fernet import Fernet
from typing import TypedDict, Any

class SafeAgentState(TypedDict):
    messages: list
    pii_encrypted: dict[str, str]  # Encrypted PII
    pii_hash: str  # SHA256 for audit

class PIIProtector:
    def __init__(self):
        self.cipher = Fernet(Fernet.generate_key())

    def sanitize_state(self, state: dict) -> SafeAgentState:
        safe_state = state.copy()
        pii_fields = {}

        # Encrypt PII
        for key, value in state.items():
            if self.contains_pii(str(value)):
                pii_fields[key] = self.cipher.encrypt(str(value).encode()).decode()
                safe_state[key] = '[PII_ENCRYPTED]'

        safe_state['pii_encrypted'] = pii_fields
        safe_state['pii_hash'] = self.hash_state(safe_state)
        return safe_state

    def contains_pii(self, text: str) -> bool:
        import re
        return bool(re.search(r'\b\d{3}-\d{2}-\d{4}|\S+@\S+\.\S+\b', text))

from typing import TypedDict, List, Dict, Any
from langgraph.prebuilt import ToolNode

APPROVED_TOOLS = {'search', 'calculator'}
TOOL_CALL_LIMITS = {'send_email': 3, 'search': 10}

class GovernedToolNode(ToolNode):
    def __init__(self, tools, call_limits: Dict[str, int] = None):
        super().__init__(tools)
        self.call_counts = {}
        self.call_limits = call_limits or TOOL_CALL_LIMITS

    def _process_tool_calls(self, state):
        tool_calls = state['next']
        filtered_calls = []

        for tool_call in tool_calls:
            tool_name = tool_call['name']

            if tool_name not in APPROVED_TOOLS:
                state['messages'].append({
                    'role': 'tool',
                    'content': f'BLOCKED: {tool_name} not in approved toolset',
                    'tool_call_id': tool_call['id']
                })
                continue

            self.call_counts[tool_name] = self.call_counts.get(tool_name, 0) + 1
            if self.call_counts[tool_name] > self.call_limits.get(tool_name, 999):
                state['messages'].append({
                    'role': 'tool',
                    'content': f'RATE LIMITED: {tool_name}',
                    'tool_call_id': tool_call['id']
                })
                continue

            filtered_calls.append(tool_call)

        state['next'] = filtered_calls
        return state

